function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const tenant_id = body.tenant_id || root.tenant_id || null;
const dayBucket = new Date().toISOString().slice(0, 10);
const event_id = body.event_id || body.run_id || ('reconciliation-' + (response_required ? 'manual-' : '') + (tenant_id || 'all') + '-' + dayBucket);
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  tenant_id,
  event_id,
  idem_key: 'reconciliation:' + event_id,
  replay,
  response_required,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Run').first().json;
const H = {
  apikey: $env.SUPABASE_SERVICE_KEY,
  Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
  accept: 'application/json',
  'content-type': 'application/json'
};
const prefer = Object.assign({}, H, { Prefer: 'return=representation' });
const helpers = this.helpers;
function enc(value) {
  return encodeURIComponent(String(value));
}
async function get(path) {
  return await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: H, json: true });
}
// Paginated fetch: PostgREST caps responses (max-rows); Range pages prevent silent row drop.
async function getAll(path, pageSize = 1000) {
  const out = [];
  for (let from = 0; ; from += pageSize) {
    const page = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: Object.assign({}, H, { Range: from + '-' + (from + pageSize - 1), 'Range-Unit': 'items' }), json: true });
    if (!Array.isArray(page) || page.length === 0) break;
    out.push(...page);
    if (page.length < pageSize) break;
  }
  return out;
}
// Exact server-side count without fetching rows (Content-Range: */N).
async function countWhere(path) {
  const res = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path + '&limit=1', headers: Object.assign({}, H, { Prefer: 'count=exact' }), json: true, returnFullResponse: true });
  const cr = (res.headers && (res.headers['content-range'] || res.headers['Content-Range'])) || '';
  const total = Number(String(cr).split('/')[1]);
  return Number.isFinite(total) ? total : null;
}
async function post(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: p.supabase_url + path, headers: prefer, body, json: true });
}

const idFilter = p.tenant_id ? '&id=eq.' + enc(p.tenant_id) : '';
const tenantFilter = p.tenant_id ? '&tenant_id=eq.' + enc(p.tenant_id) : '';
const tenants = await getAll('/rest/v1/tenants?select=id,name,plan,region,status,health_score,created_at' + idFilter);
const policies = await getAll('/rest/v1/tenant_policies?select=tenant_id,policy' + tenantFilter);
const invoices = await getAll('/rest/v1/invoices?select=tenant_id,stripe_id,status,amount,currency,attempt,created_at,updated_at' + tenantFilter);
const entitlements = await getAll('/rest/v1/entitlements?select=tenant_id,feature,enabled,updated_at' + tenantFilter);

const policyByTenant = new Map((policies || []).map((row) => [row.tenant_id, row.policy || {}]));
const invoicesByTenant = new Map();
for (const invoice of invoices || []) {
  if (!invoicesByTenant.has(invoice.tenant_id)) invoicesByTenant.set(invoice.tenant_id, []);
  invoicesByTenant.get(invoice.tenant_id).push(invoice);
}
const entitlementByTenant = new Map();
for (const ent of entitlements || []) {
  if (!entitlementByTenant.has(ent.tenant_id)) entitlementByTenant.set(ent.tenant_id, {});
  entitlementByTenant.get(ent.tenant_id)[ent.feature] = !!ent.enabled;
}

const findings = [];
for (const tenant of tenants || []) {
  const tenantInvoices = invoicesByTenant.get(tenant.id) || [];
  const ent = entitlementByTenant.get(tenant.id) || {};
  const expected = ((policyByTenant.get(tenant.id) || {}).entitlements) || {};
  const paid = tenantInvoices.filter((invoice) => invoice.status === 'paid');
  const failed = tenantInvoices.filter((invoice) => ['payment_failed', 'open', 'uncollectible'].includes(invoice.status));

  if (tenant.status === 'active' && tenantInvoices.length === 0) {
    findings.push({ tenant_id: tenant.id, tenant_name: tenant.name, severity: 'high', type: 'missing_invoice', message: 'active tenant has no billing invoice records' });
  }
  for (const invoice of failed) {
    findings.push({ tenant_id: tenant.id, tenant_name: tenant.name, severity: invoice.status === 'payment_failed' ? 'high' : 'medium', type: 'invoice_attention', stripe_id: invoice.stripe_id, status: invoice.status, amount: invoice.amount });
  }
  for (const [feature, expectedEnabled] of Object.entries(expected)) {
    const actual = ent[feature] === true;
    if (actual !== !!expectedEnabled) {
      findings.push({ tenant_id: tenant.id, tenant_name: tenant.name, severity: 'medium', type: 'entitlement_drift', feature, expected: !!expectedEnabled, actual });
    }
  }
  if (tenant.plan === 'enterprise' && paid.length === 0 && tenant.status === 'active') {
    findings.push({ tenant_id: tenant.id, tenant_name: tenant.name, severity: 'medium', type: 'erp_gap', message: 'enterprise tenant has no paid invoice in local ERP/billing mirror' });
  }
}

const sevRank = { high: 0, medium: 1, low: 2 };
findings.sort((a, b) => (sevRank[a.severity] ?? 9) - (sevRank[b.severity] ?? 9));

const summary = {
  tenant_scope: p.tenant_id || 'all',
  tenant_count: (tenants || []).length,
  invoice_count: (invoices || []).length,
  finding_count: findings.length,
  high_count: findings.filter((f) => f.severity === 'high').length,
  medium_count: findings.filter((f) => f.severity === 'medium').length,
  generated_at: new Date().toISOString()
};

const rows = await post('/rest/v1/reconciliation_runs', [{
  correlation_id: p.correlation_id,
  tenant_id: p.tenant_id || null,
  status: 'completed',
  summary,
  findings
}]);
const run = Array.isArray(rows) ? rows[0] : rows;

let telegram_delivered = false;
let notice = null;
if (p.telegram_token && p.telegram_chat && findings.length > 0) {
  const top = findings.slice(0, 5).map((f) => f.severity.toUpperCase() + ' ' + f.tenant_name + ': ' + f.type).join('\n');
  const text = ['FlowOps reconciliation', 'Findings: ' + findings.length, 'Correlation: ' + p.correlation_id, '', top].join('\n');
  try {
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + p.telegram_token + '/sendMessage', body: { chat_id: p.telegram_chat, text }, json: true });
    telegram_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else if (findings.length === 0) {
  notice = 'telegram skipped: no findings';
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}

return [{ json: { run_id: run && run.id, tenant_id: p.tenant_id || null, correlation_id: p.correlation_id, summary, findings, telegram_delivered, notice } }];

const r = $('Run Reconciliation').first().json;
return [{ json: {
  tenant_id: r.tenant_id,
  correlation_id: r.correlation_id,
  service: 'reconciliation',
  step: 'surface-drift',
  status: 'success',
  payload: { run_id: r.run_id, summary: r.summary, telegram_delivered: r.telegram_delivered, notice: r.notice }
} }];
